function limparDocsDaPasta() {
  // 1. Substitua pelo ID da pasta do Google Drive onde estão os seus roteiros
  var idDaPasta = "1G-D3NsHTpTt17unutRYsKELqfnWnc2XV"; 

  var pasta = DriveApp.getFolderById(idDaPasta);

  // 2. Pega apenas arquivos que são do tipo Google Docs (ignora PDFs, planilhas, etc)
  var arquivos = pasta.getFilesByType(MimeType.GOOGLE_DOCS);
  var contador = 0;

  // 3. Loop: Enquanto houver arquivos na pasta, ele executa a limpeza
  while (arquivos.hasNext()) {
    var arquivo = arquivos.next();
    var idDoDoc = arquivo.getId();

    // Mostra no log do Apps Script qual arquivo está sendo lido
    Logger.log("Processando documento: " + arquivo.getName());

    try {
      limparDocumentoParaSite(idDoDoc);
      contador++;
    } catch (erro) {
      Logger.log("Erro ao limpar " + arquivo.getName() + ": " + erro.toString());
    }
  }

  Logger.log("Limpeza concluída! Foram processados " + contador + " documentos.");
}


// --- A SUA FUNÇÃO DE LIMPEZA INTACTA ABAIXO ---

function limparDocumentoParaSite(docId) {
  var doc = DocumentApp.openById(docId);
  var body = doc.getBody();

  // 1. Remover Imagens do Corpo (Simples e Flutuantes)
  var imagens = body.getImages();
  for (var i = 0; i < imagens.length; i++) {
    imagens[i].removeFromParent();
  }

  var paragrafos = body.getParagraphs();
  for (var p = 0; p < paragrafos.length; p++) {
    // 1.1 Remover Imagens Flutuantes
    var posicionadas = paragrafos[p].getPositionedImages();
    for (var pi = 0; pi < posicionadas.length; pi++) {
      paragrafos[p].removePositionedImage(posicionadas[pi].getId());
    }

    // 1.2 Remover Desenhos (Inline Drawings - "textos em formato de imagem")
    var numFilhos = paragrafos[p].getNumChildren();
    // Varre de trás para frente para evitar problemas de índice ao deletar
    for (var f = numFilhos - 1; f >= 0; f--) {
      var filho = paragrafos[p].getChild(f);
      if (filho.getType() === DocumentApp.ElementType.INLINE_DRAWING) {
        filho.removeFromParent();
      }
    }
  }

  // 1.3 Remover Imagens do Cabeçalho e Rodapé
  var header = doc.getHeader();
  if (header) {
    var imgsHeader = header.getImages();
    for (var h = 0; h < imgsHeader.length; h++) { imgsHeader[h].removeFromParent(); }
  }
  var footer = doc.getFooter();
  if (footer) {
    var imgsFooter = footer.getImages();
    for (var f = 0; f < imgsFooter.length; f++) { imgsFooter[f].removeFromParent(); }
  }

  // 2. Limpar a tabela de Preços (manter apenas as datas)
  var tabelas = body.getTables();
  for (var t = 0; t < tabelas.length; t++) {
    var tabela = tabelas[t];
    var textoPrimeiraLinha = tabela.getRow(0).getText();

    if (textoPrimeiraLinha.indexOf("PARTE TERRESTRE") !== -1 || textoPrimeiraLinha.indexOf("Preços por pessoa") !== -1) {
      var numLinhas = tabela.getNumRows();
      for (var r = 0; r < numLinhas; r++) {
        var linha = tabela.getRow(r);
        var numCelulas = linha.getNumCells();
        if (numCelulas > 1) {
          // Remove as colunas de valores, deixando só a primeira (índice 0)
          for (var c = numCelulas - 1; c >= 1; c--) {
            linha.removeCell(c);
          }
        }
      }
    }
  }

 // 3. Radar de Corte: Remover tudo do final com base em várias palavras-chave
  var palavrasChave = [
    "PASSEIOS OPCIONAIS", 
    "Informações Gerais", 
    "Importante", 
    "ENTRE EM CONTATO CONOSCO!",
    "SERVIÇOS OPCIONAIS – MEIA PENSÃO", // Nova palavra-chave
    "SERVIÇOS OPCIONAIS – PENSÃO COMPLETA", // Nova palavra-chave
    "Preços por pessoa em US$ (Dólares Americanos)" // Reforço para garantir o corte nas tabelas de opcionais
  ];

  var indiceCorte = -1;

  for (var i = 0; i < palavrasChave.length; i++) {
    var pesquisa = body.findText(palavrasChave[i]);
    if (pesquisa) {
      var elementoEncontrado = pesquisa.getElement();

      // Sobe na estrutura até achar o elemento principal (filho direto do Body)
      var elementoRaiz = elementoEncontrado;
      while (elementoRaiz.getParent() && elementoRaiz.getParent().getType() !== DocumentApp.ElementType.BODY_SECTION) {
        elementoRaiz = elementoRaiz.getParent();
      }

      var idx = body.getChildIndex(elementoRaiz);

      // Atualiza o índice de corte se encontrou uma palavra que aparece ANTES no documento
      if (indiceCorte === -1 || idx < indiceCorte) {
        indiceCorte = idx;
      }
    }
  }

  // Se encontrou alguma das palavras-chave, apaga tudo dali para baixo
  if (indiceCorte !== -1) {
    var numElementos = body.getNumChildren();
    for (var k = numElementos - 1; k >= indiceCorte; k--) {
      var filhoParaRemover = body.getChild(k);

      try {
        body.removeChild(filhoParaRemover);
      } catch (erro) {
        // Tratativa para o último parágrafo estrutural do Google Docs
        if (filhoParaRemover.getType() === DocumentApp.ElementType.PARAGRAPH) {
          filhoParaRemover.asParagraph().clear();
        }
      }
    }
  }

  doc.saveAndClose();
  return ContentService.createTextOutput("Documento limpo com sucesso!");
}
